'use client'
import { cn } from '@cascivo/core'
import type { HTMLAttributes, ReactNode } from 'react'
import styles from './stat.module.css'

export interface StatProps extends Omit<HTMLAttributes<HTMLDivElement>, 'children'> {
  label: string
  value: string | number
  delta?: string
  trend?: 'up' | 'down' | 'flat'
  helpText?: string
  /** Trailing visual, e.g. a `Sparkline` from `@cascivo/charts`. Purely decorative — mark it `aria-hidden` yourself if it duplicates the value/delta already announced. */
  visual?: ReactNode
}

export function Stat({
  label,
  value,
  delta,
  trend = 'flat',
  helpText,
  visual,
  className,
  ...props
}: StatProps) {
  return (
    <div className={cn(styles['stat'], className as string | undefined)} {...props}>
      <span className={styles['label']}>{label}</span>
      <span className={styles['value']}>{value}</span>
      {delta && (
        <span data-trend={trend} className={styles['delta']}>
          <span aria-hidden="true" className={styles['arrow']}>
            {trend === 'up' ? '▲' : trend === 'down' ? '▼' : '–'}
          </span>
          {delta}
        </span>
      )}
      {helpText && <span className={styles['help']}>{helpText}</span>}
      {visual && <span className={styles['visual']}>{visual}</span>}
    </div>
  )
}

@layer cascivo.component {
  .stat {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-1);
    font-family: var(--cascivo-font-sans);
  }

  .label {
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text-subtle);
    line-height: var(--cascivo-leading-tight);
  }

  .value {
    font-size: var(--cascivo-text-2xl);
    font-weight: var(--cascivo-font-semibold);
    color: var(--cascivo-color-text);
    line-height: var(--cascivo-leading-tight);
    font-variant-numeric: tabular-nums;
  }

  .delta {
    display: inline-flex;
    align-items: center;
    gap: var(--cascivo-space-1);
    font-size: var(--cascivo-text-sm);
    font-weight: var(--cascivo-font-medium);
    font-variant-numeric: tabular-nums;

    &[data-trend='up'] {
      color: var(--cascivo-color-success-foreground);
    }

    &[data-trend='down'] {
      color: var(--cascivo-color-destructive-foreground);
    }

    &[data-trend='flat'] {
      color: var(--cascivo-color-text-subtle);
    }
  }

  .arrow {
    font-size: var(--cascivo-text-xs);
    line-height: 1;
  }

  .help {
    font-size: var(--cascivo-text-xs);
    color: var(--cascivo-color-text-subtle);
    line-height: var(--cascivo-leading-tight);
  }

  .visual {
    margin-block-start: var(--cascivo-space-1);
  }
}
